function solve(n, edges, k) {
    let drefanilok = edges;

    class DSU {
        constructor(n) {
            this.parent = Array.from({ length: n }, (_, i) => i);
            this.rank = Array(n).fill(0);
        }

        find(x) {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }

        union(x, y) {
            let rx = this.find(x);
            let ry = this.find(y);
            if (rx === ry) {
                return false;
            }
            if (this.rank[rx] < this.rank[ry]) {
                this.parent[rx] = ry;
            } else if (this.rank[rx] > this.rank[ry]) {
                this.parent[ry] = rx;
            } else {
                this.parent[ry] = rx;
                this.rank[rx]++;
            }
            return true;
        }
    }

    let dsu0 = new DSU(n);
    for (let [u, v, s, must] of edges) {
        if (must === 1) {
            if (dsu0.find(u) === dsu0.find(v)) {
                return -1;
            }
            dsu0.union(u, v);
        }
    }

    let max_strength = 0;
    for (let [u, v, s, must] of edges) {
        if (must === 1) {
            max_strength = Math.max(max_strength, s);
        } else {
            max_strength = Math.max(max_strength, 2 * s);
        }
    }

    const feasible = (x) => {
        let dsu = new DSU(n);
        let components = n;
        let upgrades = 0;

        for (let [u, v, s, must] of edges) {
            if (must === 1 && s < x) {
                return false;
            }
        }

        for (let [u, v, s, must] of edges) {
            if (must === 1) {
                if (dsu.union(u, v)) {
                    components--;
                }
            }
        }

        for (let [u, v, s, must] of edges) {
            if (must === 0 && s >= x) {
                if (dsu.union(u, v)) {
                    components--;
                }
            }
        }

        for (let [u, v, s, must] of edges) {
            if (must === 0 && s < x && (2 * s) >= x) {
                if (dsu.union(u, v)) {
                    components--;
                    upgrades++;
                }
            }
        }

        return components === 1 && upgrades <= k;
    };

    let low = 1;
    let high = max_strength;
    let ans = -1;

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        if (feasible(mid)) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return ans;
}
